// Analisar métricas de campanha
const whatsappStatus = $input.first().json;
const campaignLogs = $input.last().json;

// Calcular métricas de hoje
const hoje = new Date().toISOString().split('T')[0];
const logsHoje = campaignLogs.filter(log => 
  log.timestamp && log.timestamp.startsWith(hoje)
);

// Métricas por segmento
const metricasPorSegmento = {
  QUENTE: logsHoje.filter(log => log.segment === 'QUENTE').length,
  MORNO: logsHoje.filter(log => log.segment === 'MORNO').length,
  FRIO: logsHoje.filter(log => log.segment === 'FRIO').length,
  CONGELADO: logsHoje.filter(log => log.segment === 'CONGELADO').length
};

// Calcular taxa de sucesso (simulação baseada no segmento)
const calcularTaxaSucesso = (segmento, quantidade) => {
  const taxas = {
    QUENTE: 0.35,    // 35% taxa de resposta esperada
    MORNO: 0.25,     // 25% taxa de resposta esperada
    FRIO: 0.15,      // 15% taxa de resposta esperada
    CONGELADO: 0.05  // 5% taxa de resposta esperada
  };
  return Math.floor(quantidade * (taxas[segmento] || 0.1));
};

// Projeções de reativação
const projecaoReativacao = {
  QUENTE: calcularTaxaSucesso('QUENTE', metricasPorSegmento.QUENTE),
  MORNO: calcularTaxaSucesso('MORNO', metricasPorSegmento.MORNO),
  FRIO: calcularTaxaSucesso('FRIO', metricasPorSegmento.FRIO),
  CONGELADO: calcularTaxaSucesso('CONGELADO', metricasPorSegmento.CONGELADO)
};

const totalReativacaoProjetada = Object.values(projecaoReativacao).reduce((a, b) => a + b, 0);
const receitaProjetada = totalReativacaoProjetada * 129; // R$ 129 mensalidade

// Métricas de performance
const analytics = {
  timestamp: new Date().toISOString(),
  data_analise: hoje,

  // Status do sistema
  whatsapp_status: whatsappStatus.status || 'unknown',
  whatsapp_conectado: whatsappStatus.isConnected || false,

  // Métricas de campanha do dia
  mensagens_enviadas_hoje: logsHoje.length,
  por_segmento: metricasPorSegmento,

  // Projeções
  projecao_reativacao: projecaoReativacao,
  total_reativacao_projetada: totalReativacaoProjetada,
  receita_projetada_mensal: receitaProjetada,

  // KPIs
  taxa_envio_diaria: logsHoje.length,
  meta_diaria: 50, // Meta de 50 mensagens por dia
  percentual_meta: Math.round((logsHoje.length / 50) * 100),

  // ROI estimado
  custo_operacional_estimado: 500, // R$ 500/mês custo operacional
  roi_projetado: receitaProjetada > 500 ? Math.round(((receitaProjetada - 500) / 500) * 100) : 0,

  // Alertas
  alertas: [
    whatsappStatus.isConnected ? null : 'WhatsApp desconectado',
    logsHoje.length < 10 ? 'Baixo volume de mensagens hoje' : null,
    totalReativacaoProjetada < 20 ? 'Meta de reativação em risco' : null
  ].filter(alert => alert !== null),

  academia: 'Full Force Academia - Matupá-MT'
};

return { json: analytics };

